import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def execute_cli_fixture(name):
    script = []
    for line in (ROOT / "tests" / name).read_text(encoding="utf-8").splitlines():
        directive = line.strip()
        if directive.startswith(".read "):
            script.append((ROOT / directive[6:].strip()).read_text(encoding="utf-8"))
        elif not directive.startswith("."):
            script.append(line)
    connection = sqlite3.connect(":memory:")
    try:
        connection.executescript("\n".join(script))
    finally:
        connection.close()


def test_final_sql_contract():
    execute_cli_fixture("final.sql")
